@FunctionalInterface
public interface DataProcessor<T> {
    // Required: ONE abstract method
    Result process(T data);

    // Allowed: Multiple default methods
    default Result processWithLogging(T data) {
        System.out.println("Processing: " + data);
        Result result = process(data);
        System.out.println("Result: " + result);
        return result;
    }

    default Result processWithRetry(T data, int maxRetries) {
        for (int i = 0; i < maxRetries; i++) {
            try {
                return process(data);
            } catch (Exception e) {
                if (i == maxRetries - 1) throw e;
            }
        }
        return null;
    }

    // Allowed: Static method
    static <T> DataProcessor<T> noOp() {
        return data -> new Result("No operation");
    }
}

