boolean result1 = lambdaPredicate.test(10);  // true

// EQUIVALENT ANONYMOUS CLASS
Predicate<Integer> anonPredicate = new Predicate<Integer>() {
    @Override
    public boolean test(Integer n) {
        return n > 5;
    }
};
boolean result2 = anonPredicate.test(10);  // true

// LAMBDA: No new scope for 'this'
class MyClass {
    private String name = "MyClass";
    public void demonstrateLambda() {
        Consumer<String> lambda = s -> System.out.println(this.name);  // Refers to MyClass
    }
}

// LAMBDA: Simple and readable
List<Integer> numbers = Arrays.asList(1, 2, 3, 4, 5);
List<Integer> doubled = numbers.stream()
    .map(n -> n * 2)
    .collect(Collectors.toList());

// ANONYMOUS CLASS: Verbose
List<Integer> doubled = numbers.stream()
    .map(new Function<Integer, Integer>() {
        @Override
        public Integer apply(Integer n) {
            return n * 2;
        }
    })
    .collect(Collectors.toList());

class DataProcessor {
    // Instance variable
    private int processedCount = 0;
    private String status = "IDLE";

    // Static variable
    private static int totalProcessed = 0;

    public void demonstrateAccess(List<Integer> numbers) {
        // Lambda accessing and modifying instance variables
        Consumer<Integer> processor = n -> {
            processedCount++;  // Can modify instance variable
            status = "PROCESSING";  // Can modify instance variable
            totalProcessed++;  // Can modify static variable
            System.out.println(this.processedCount);  // Explicit 'this'
        };

        numbers.forEach(processor);
        System.out.println("Processed: " + processedCount);  // Access outside lambda
    }

    // Using static variable in lambda
    public void processAsync(Integer number) {
        CompletableFuture.supplyAsync(() -> {
            totalProcessed++;  // Can modify static variable
            return "Result: " + number;
        });
    }
}

// Usage
DataProcessor processor = new DataProcessor();
processor.demonstrateAccess(Arrays.asList(1, 2, 3, 4, 5));
// processedCount now = 5, totalProcessed = 5

// VALID: Lambda with functional interface context
Predicate<Integer> p = n -> n > 5;  // Clear target: Predicate<Integer>
Function<String, Integer> f = s -> s.length();  // Function
Consumer<String> c = s -> System.out.println(s);  // Consumer

// INVALID: Lambda without functional interface target
// Object obj = n -> n > 5;  // COMPILE ERROR: Object not functional interface
// String s = x -> x.toUpperCase();  // COMPILE ERROR

// VALID: Method parameter provides context
List<Integer> numbers = Arrays.asList(1, 2, 3, 4, 5);
numbers.stream()
    .filter(n -> n > 2)  // Context: filter expects Predicate<Integer>
    .forEach(System.out::println);  // Context: forEach expects Consumer<Integer>

// VALID: Assignment provides context
Comparator<String> comp = (s1, s2) -> s1.length() - s2.length();
// Target type: Comparator<String> from assignment

// INVALID: No context
// var result = n -> n * 2;  // COMPILE ERROR: Cannot infer target type

// WORKAROUND: Explicit cast
Object obj = (Predicate<Integer>) n -> n > 5;  // Cast provides context

List<String> words = Arrays.asList("apple", "banana", "cherry");
List<Integer> numbers = Arrays.asList("10", "20", "30");

// STATIC METHOD REFERENCE
// Instead of: s -> Integer.parseInt(s)
List<Integer> parsed = numbers.stream()
    .map(Integer::parseInt)  // Method reference to static method
    .collect(Collectors.toList());

// INSTANCE METHOD REFERENCE
PrintStream out = System.out;
// Instead of: s -> out.println(s)
words.forEach(out::println);  // Method reference to instance method

// CLASS INSTANCE METHOD REFERENCE
// Instead of: s -> s.toUpperCase()
List<String> uppercase = words.stream()
    .map(String::toUpperCase)  // ClassName::instanceMethod
    .collect(Collectors.toList());

// CONSTRUCTOR REFERENCE
Supplier<LocalDateTime> now = LocalDateTime::now;  // Constructor reference
List<LocalDateTime> timestamps = Stream.generate(now)
    .limit(3)
    .collect(Collectors.toList());

// PRACTICAL EXAMPLE
List<Integer> nums = Arrays.asList(5, 2, 8, 1, 9);
// Using lambda
List<Integer> sorted1 = nums.stream()
    .sorted((a, b) -> Integer.compare(a, b))
    .collect(Collectors.toList());
// Using method reference - cleaner
List<Integer> sorted2 = nums.stream()
    .sorted(Integer::compare)  // Direct method reference
    .collect(Collectors.toList());

// FUNCTIONAL PIPELINE with method references
words.stream()
    .map(String::toLowerCase)       // Reference
    .filter(String::isEmpty).negate()  // Reference
    .map(String::toCharArray)       // Reference
    .forEach(System.out::println);  // Reference
